let visionSeedSearchCache = null;
function buildVisionSeedSearchIndex(){
  const seed=activeVisionSeedMemory();
  if(!seed) return [];
  if(visionSeedSearchCache && visionSeedSearchCache.version===seed.version) return visionSeedSearchCache.rows;
  const rows=(seed.products||[]).map((p,idx)=>{
    const brand=String(p.brand||'');
    const format=Array.isArray(p.formats)?String(p.formats[0]||''):'';
    const text=[p.name,brand,p.category,p.subcategory,p.packageType,format,...(p.aliases||[]),...(p.ocrKeywords||[]),...(p.visualHints||[])].join(' ');
    const norm=normalizeLearnText(text);
    const tokens=[...new Set(norm.split(/\s+/).filter(t=>t.length>=2))];
    return {p,idx,norm,tokens,nameNorm:normalizeLearnText(p.name||''),brandNorm:normalizeLearnText(brand),category:seedCategoryToApp(p.category||''),format};
  });
  visionSeedSearchCache={version:seed.version, rows};
  return rows;
}
function bestVisionSeedMatchForResult(result={}){
  const text=normalizeLearnText([result.productName,result.brand,result.variant,result.productType,result.packageType,result.estimatedSize,...(result.detectedText||[]),...(result.visibleEvidence||[])].join(' '));
  if(!text || text.length<3) return null;
  const words=new Set(text.split(/\s+/).filter(t=>t.length>=2));
  let best=null;
  for(const row of buildVisionSeedSearchIndex()){
    let score=0;
    if(row.nameNorm && (text.includes(row.nameNorm) || row.nameNorm.includes(text))) score+=9;
    if(row.brandNorm && text.includes(row.brandNorm)) score+=5;
    if(result.category && row.category===result.category) score+=1.2;
    for(const tok of row.tokens){
      if(words.has(tok)) score += tok.length>=6 ? 1.45 : 0.8;
    }
    // Penalizza match troppo generici: devono esserci nome/marca/formato o più token forti.
    if(row.brandNorm && !text.includes(row.brandNorm)) score-=0.8;
    if(row.format && text.includes(normalizeLearnText(row.format))) score+=2.2;
    if(!best || score>best.score) best={row,score};
  }
  if(!best || best.score<5.2) return null;
  return best;
}
function applyDirectSeedKnowledge(result={}){
  const match=bestVisionSeedMatchForResult(result); if(!match) return result;
  const p=match.row.p; const confirmedMemory=result.memoryVision && !result.seedVision;
  const seedFormat=(Array.isArray(p.formats)?p.formats[0]:'')||'';
  if((!result.productName || isBadScanName(result.productName)) && p.name) result.productName=p.name;
  if(!result.brand && p.brand && p.brand!=='Generico') result.brand=p.brand;
  if(!confirmedMemory && (!result.estimatedSize || /da confermare|circa|possibile/i.test(String(result.estimatedSize))) && seedFormat) result.estimatedSize=seedFormat;
  if((!result.unit || result.unit==='pz') && p.defaultUnit) result.unit=p.defaultUnit;
  if(result.category==='food' && p.category) result.category=match.row.category || seedCategoryToApp(p.category);
  if(!result.packageType && p.packageType) result.packageType=p.packageType;
  result.seedVision=true; result.bestMatchName=result.bestMatchName||p.name; result.bestMatchSource=result.bestMatchSource||'seed MEGA prodotti comuni'; result.bestMatchScore=Math.max(Number(result.bestMatchScore||0), Math.min(99, Math.round(match.score*7)));
  result.confidence=Math.max(Number(result.confidence||0), Math.min(.88, .58 + match.score/55));
  if(result.confidence<.90) result.shouldAskConfirmation=true;
  return result;
}
function seedLearnedRow(p){
  const appCat=seedCategoryToApp(p.category||'food');
  const format=(Array.isArray(p.formats)?p.formats[0]:'') || '';
  const brand=(p.brand && p.brand!=='Generico') ? p.brand : '';
  const name=String(p.name||'').trim();
  const key='seed | '+normalizeLearnText([name,brand,format].filter(Boolean).join(' '));
  return {
    key, seed:true, seedVersion:activeVisionSeedMemory()?.version||'seed', seedConfidence:.55,
    productName:name, brand, variant:String(p.subcategory||''), category:appCat, originalSeedCategory:p.category||'', unit:p.defaultUnit||'pz',
    productType:String(p.subcategory||''), packageType:String(p.packageType||''), estimatedSize:format,
    formats:Array.isArray(p.formats)?p.formats.slice(0,8):[], ocrKeywords:Array.isArray(p.ocrKeywords)?p.ocrKeywords.slice(0,12):[],
    isLiquid:['water','soft_drinks','dairy'].includes(p.category), seenCount:0, seedSeenCount:1, lastConfirmedAt:0,
    aliases:Array.isArray(p.aliases)?p.aliases.slice(0,10):[name], visualHints:Array.isArray(p.visualHints)?p.visualHints.slice(0,10):[], knownColors:Array.isArray(p.knownColors)?p.knownColors.slice(0,8):[], storage:p.storage||''
  };
}
function ensureSeedVisionMemory(force=false){
  const seed=activeVisionSeedMemory();
  if(!seed) return false;
  const seedProducts = Array.isArray(seed.products) ? seed.products : [];
  const seedCategories = Array.isArray(seed.categories) ? seed.categories.length : 0;
  aiMemory.seedMemory=Object.assign({version:'',loaded:false,products:0,categories:0,lastLoadedAt:0}, aiMemory.seedMemory||{});
  const b=ensureVisionBrain();
  b.seedVersion=seed.version || 'seed';
  b.seedProducts=seedProducts.length;
  b.seedModelProfiles=megaVisionTotalProfiles();
  b.seedCategories=seedCategories;
  b.seedRules=seed.rules||{};
  b.seedLoadedAt=b.seedLoadedAt||Date.now();
  if(!force && aiMemory.seedMemory.loaded && aiMemory.seedMemory.version===seed.version && Number(aiMemory.seedMemory.products||0)===seedProducts.length){
    aiMemory.seedMemory.products=seedProducts.length;
    aiMemory.seedMemory.totalProfiles=megaVisionTotalProfiles();
    aiMemory.seedMemory.categories=seedCategories;
    aiMemory.seedMemory.indexed=true;
    saveAiMemory();
    return true;
  }
  aiMemory.learnedProducts=Array.isArray(aiMemory.learnedProducts)?aiMemory.learnedProducts:[];
  const byKey=new Map(aiMemory.learnedProducts.map((r,i)=>[String(r.key||''), i]));
  let added=0, updated=0;
  const seedRowsForLocalMemory = seedProducts.slice(0,900);
  for(const p of seedRowsForLocalMemory){
    if(!p?.name) continue;
    const row=seedLearnedRow(p);
    const idx=byKey.get(row.key);
    if(idx===undefined){ aiMemory.learnedProducts.push(row); added++; }
    else { aiMemory.learnedProducts[idx]=Object.assign({}, row, aiMemory.learnedProducts[idx], {seed:true, seedVersion:row.seedVersion, formats:row.formats, ocrKeywords:row.ocrKeywords}); updated++; }
  }
  b.seedLoadedAt=Date.now();
  aiMemory.seedMemory={version:seed.version||'seed',loaded:true,products:seedProducts.length,totalProfiles:megaVisionTotalProfiles(),categories:seedCategories,lastLoadedAt:Date.now(),added,updated,indexed:true,mode:'mega-virtual-index'};
  aiMemory.learnedProducts.sort((a,b)=>{
    if(!!a.seed!==!!b.seed) return a.seed?1:-1;
    return Number(b.lastConfirmedAt||0)-Number(a.lastConfirmedAt||0);
  });
  aiMemory.learnedProducts=aiMemory.learnedProducts.slice(0,900);
  saveAiMemory();
  return true;
}


function ensureVoiceProfile(){
  aiMemory.voiceProfile=Object.assign(defaultAiMemory().voiceProfile, aiMemory.voiceProfile||{});
  aiMemory.voiceProfile.heard=Array.isArray(aiMemory.voiceProfile.heard)?aiMemory.voiceProfile.heard:[];
  aiMemory.voiceProfile.corrections=Array.isArray(aiMemory.voiceProfile.corrections)?aiMemory.voiceProfile.corrections:[];
  aiMemory.voiceProfile.intentPhrases=aiMemory.voiceProfile.intentPhrases||{};
  aiMemory.voiceProfile.fieldPhrases=aiMemory.voiceProfile.fieldPhrases||{};
  aiMemory.voiceProfile.productAliases=aiMemory.voiceProfile.productAliases||{};
  aiMemory.voiceProfile.speakerStyle=Object.assign(defaultAiMemory().voiceProfile.speakerStyle, aiMemory.voiceProfile.speakerStyle||{});
  return aiMemory.voiceProfile;
}
function addCounter(obj,key,inc=1){ if(!key) return; obj[key]=Number(obj[key]||0)+inc; }
function learnVoiceLocally(raw='', intent='heard', field='', value=''){
  const text=String(raw||'').trim(); if(!text) return;
  const vp=ensureVoiceProfile(); const norm=normalizeText(text).slice(0,120);
  vp.heard.unshift({text:text.slice(0,160), norm, intent, field, value:String(value||'').slice(0,120), at:Date.now()});
  vp.heard=vp.heard.slice(0,160);
  addCounter(vp.intentPhrases, `${intent}:${norm}`);
  if(field){ vp.fieldPhrases[field]=vp.fieldPhrases[field]||{}; addCounter(vp.fieldPhrases[field], norm); }
  if(/bro|fra|cioe|cioè|capito|ok|okay|va bene/.test(norm)) vp.speakerStyle.italianSlang=Number(vp.speakerStyle.italianSlang||0)+1;
  if(norm.split(/\s+/).length<=3) vp.speakerStyle.shortCommands=Number(vp.speakerStyle.shortCommands||0)+1;
  if(/non e|non è|correggi|cambia|metti/.test(norm)) vp.speakerStyle.corrections=Number(vp.speakerStyle.corrections||0)+1;
  vp.updatedAt=Date.now();
  saveAiMemory();
}
function rememberVoiceCorrection(raw='', field='', value='', before=''){
  const vp=ensureVoiceProfile();
  vp.corrections.unshift({raw:String(raw||'').slice(0,180), field, value:String(value||'').slice(0,120), before:String(before||'').slice(0,120), at:Date.now()});
  vp.corrections=vp.corrections.slice(0,180);
  learnVoiceLocally(raw,'correction',field,value);
}
function mergeServerLearning(payload={}){
  if(payload?.memory){
    const localVision=aiMemory.visionBrain; const localVoice=aiMemory.voiceProfile;
    aiMemory=Object.assign(aiMemory,payload.memory);
    aiMemory.visionBrain=Object.assign(defaultAiMemory().visionBrain, aiMemory.visionBrain||{}, localVision||{});
    aiMemory.voiceProfile=Object.assign(defaultAiMemory().voiceProfile, aiMemory.voiceProfile||{}, localVoice||{});
    saveAiMemory();
  }
}
async function syncAutonomyLearningToServer(payload={}, quiet=true){
  try{
    if(!settings.apiEndpoint || !settings.householdId || !settings.token) return false;
    const res=await fetch(`${settings.apiEndpoint.replace(/\/$/,'')}/ai/learn/autonomy`,{
      method:'POST', headers:{'Content-Type':'application/json','Authorization':`Bearer ${settings.token||''}`},
      body:JSON.stringify({householdId:settings.householdId, memory:aiMemory, payload})
    });
    if(!res.ok) return false;
    const data=await res.json();
    if(data.ok){
      ensureVisionBrain().serverSyncs=Number(ensureVisionBrain().serverSyncs||0)+1; ensureVisionBrain().serverLastSyncAt=Date.now();
      ensureVoiceProfile().serverSyncs=Number(ensureVoiceProfile().serverSyncs||0)+1;
      mergeServerLearning(data); saveAiMemory(); refreshVisionBrainPanel();
      return true;
    }
  }catch(e){ if(!quiet) console.warn('server learning sync failed',e); }
  return false;
}
function t(k){ return translations[settings.lang]?.[k] || translations.it[k] || k; }
function nameOf(item){ return item.names?.[settings.lang] || item.names?.it || item.id; }
function catName(cat){ return t('category_'+cat); }
function cryptoId(){ return 'i_'+Math.random().toString(36).slice(2,10); }
function $(s){ return document.querySelector(s); }
function $all(s){ return [...document.querySelectorAll(s)]; }
function esc(s=''){ return String(s).replace(/[&<>"']/g, m => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m])); }

let toastTimer=null;
function toast(msg){
  const el=$('#toast');
  if(!el){ console.log('Toast:', msg); return; }
  el.textContent=String(msg||'');
  el.classList.add('show');
  clearTimeout(toastTimer);
  toastTimer=setTimeout(()=>el.classList.remove('show'),2800);
}
function setBusyButton(btn, busy, text){
  if(!btn) return;
  btn.disabled=!!busy;
  btn.classList.toggle('is-busy', !!busy);
  const main=btn.querySelector('.btn-main') || btn;
  if(busy){
    if(!btn.dataset.originalText) btn.dataset.originalText=main.textContent || 'Registrati';
    main.textContent=text || 'Invio in corso…';
  }else{
    main.textContent=text || btn.dataset.originalText || 'Registrati';
    delete btn.dataset.originalText;
  }
}
function emailLooksValid(value){ return /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/i.test(String(value||'')); }
function phoneLooksValid(prefix, number){ return /^\+[1-9]\d{7,14}$/.test(String(prefix||'+39') + String(number||'').replace(/\D+/g,'')); }
function passwordLooksStrong(pwd){ return String(pwd||'').length>=8 && /[A-Za-z]/.test(pwd) && /\d/.test(pwd); }
function setPhoneVerificationVisible(show){ const f=$('#verifyPhoneForm'); if(f) f.classList.toggle('hidden', !show); }
function daysBetween(a,b){ return Math.max(1,(b-a)/86400000); }
function clampNumber(value,min,max,fallback){ const n=Number(value); return Number.isFinite(n) ? Math.max(min, Math.min(max, n)) : fallback; }
function normalizeHouseholdSettings(){
  settings.people = clampNumber(settings.people, 1, 20, 1);
  settings.animals = clampNumber(settings.animals, 0, 30, 0);
  return { people:settings.people, animals:settings.animals };
}
function aiEventsFor(id,type){ return (aiMemory.events||[]).filter(e=>e.itemId===id && (!type || e.type===type)); }
function learnedDailyConsumption(item){
  const now=Date.now(), since=now-1000*60*60*24*45;
  const consumeEvents=aiEventsFor(item.id).filter(e=>e.at>=since && e.type==='consume');
  const total=consumeEvents.reduce((s,e)=>s+Math.abs(Number(e.delta)||0),0);
  if(total<=0) return 0;
  const first=Math.min(...consumeEvents.map(e=>e.at));
  return total / daysBetween(first, now);
}
function baseDailyConsumption(item){
  const {people,animals}=normalizeHouseholdSettings();
  const label=normalizeText(`${item.id||''} ${item.category||''} ${nameOf(item)||''}`);
  if(item.kind==='water' || label.includes('acqua')) return Math.max(.4, people * 1.5);
  if(item.kind==='petfood' || label.includes('crocchette')) return Math.max(.08, animals * .28);
  if(label.includes('sacchetti')) return Math.max(.05, animals * 2);
  if(item.category==='pets') return Math.max(.03, animals * .15);
  if(item.category==='drinks') return Math.max(.15, people * .55);
  if(item.category==='fruit' || item.category==='veg') return Math.max(.12, people * .28);
  if(item.category==='food') return Math.max(.08, people * .18);
  if(item.category==='house') return Math.max(.03, people * .06);
  if(item.category==='aquarium') return .035;
  if(item.category==='pharmacy') return .018;
  return Math.max(.03, people * .08);
}
function aiVelocity(item){
  const learned=learnedDailyConsumption(item);
  const base=baseDailyConsumption(item);
  if(learned>0) return Math.max(.01, (learned*.72) + (base*.28));
  return Math.max(.01, base*.55);
}
function targetDaysFor(item){
  const label=normalizeText(`${item.id||''} ${item.category||''} ${nameOf(item)||''}`);
  if(item.kind==='water' || label.includes('acqua')) return 7;
  if(item.kind==='petfood' || item.category==='pets') return 18;
  if(item.category==='fruit' || item.category==='veg') return 4;
  if(item.category==='food') return 10;
  if(item.category==='house') return 24;
  if(item.category==='aquarium') return 30;
  if(item.category==='pharmacy') return 35;
  return 12;
}
function alertDaysFor(item){
  const target=targetDaysFor(item);
  if(item.category==='fruit' || item.category==='veg') return Math.min(2,target);
  if(item.kind==='water') return 2;
  if(item.kind==='petfood' || item.category==='pets') return 7;
  return Math.max(2, Math.round(target*.35));
}
function rememberEvent(type,item,delta=0,note=''){
  aiMemory.events = aiMemory.events || [];
  aiMemory.events.push({type,itemId:item?.id||null,itemName:item?nameOf(item):'',delta:Number(delta)||0,note,at:Date.now()});
  aiMemory.events = aiMemory.events.slice(-800);
  aiMemory.consumptionProfile = aiMemory.consumptionProfile || {version:27, learnedItems:{}, lastAnalysisAt:0};
  aiMemory.consumptionProfile.lastAnalysisAt = Date.now();
  saveAiMemory();
}

function smartThreshold(item){
  if(!settings.autoSmart) return Math.max(1, Number(item.baseThreshold)||1);
  normalizeHouseholdSettings();
  let th = Math.max(1, Number(item.baseThreshold)||1);
  if(item.perPersonMin) th = Math.max(th, Math.ceil(item.perPersonMin * settings.people));
  if(item.perAnimalMin) th = Math.max(th, Math.ceil(item.perAnimalMin * settings.animals));
  if(Number(item.usage||0) >= 6) th = Math.max(th, (Number(item.baseThreshold)||1) + 2);
  if(item.kind === 'water') th = Math.max(th, settings.people * 2);
  if(item.kind === 'petfood') th = Math.max(th, settings.animals * 4);
  th = Math.max(th, Math.ceil(aiVelocity(item) * alertDaysFor(item)));
  return Math.ceil(th);
}
function statusOf(item){ return Number(item.qty||0) <= smartThreshold(item) ? 'buy' : 'home'; }
function buyItems(){ return state.filter(i => statusOf(i)==='buy'); }
function daysLeft(item){ const v=aiVelocity(item); return v>0 ? Math.max(0, Number(item.qty||0)/v) : null; }
function recommendedQty(item){
  normalizeHouseholdSettings();
  const base=Number(item.recommendedBuy||item.maxQty||item.baseThreshold||1);
  let r = Math.max(base, smartThreshold(item));
  if(item.kind==='water') r = Math.max(r, settings.people * 7);
  if(item.kind==='petfood') r = Math.max(r, settings.animals * 6);
  const velocity = aiVelocity(item);
  r = Math.max(r, Math.ceil(velocity * targetDaysFor(item)));
  return Math.max(1, Math.ceil(r));
}
function consumptionIntel(item){
  const th=smartThreshold(item), rec=recommendedQty(item), days=daysLeft(item), qty=Number(item.qty||0);
  const missing=Math.max(0, rec-qty);
  const urgency = qty<=0 ? 100 : statusOf(item)==='buy' ? Math.min(99, 76 + Math.max(0, th-qty)*6) : Math.max(1, Math.round(100 - Math.min(100, (days??targetDaysFor(item))*7)));
  let level='ok', label='Scorta ok', emoji='✅';
  if(qty<=0){ level='critical'; label='Finito'; emoji='🚨'; }
  else if(statusOf(item)==='buy'){ level='low'; label='Da comprare'; emoji='⚠️'; }
  else if(days!==null && days<alertDaysFor(item)+1){ level='watch'; label='Da controllare'; emoji='👀'; }
  const basis=learnedDailyConsumption(item)>0 ? 'consumo reale registrato' : 'stima iniziale su persone/animali';
  const reason=`${emoji} ${label}: ${days!==null?`circa ${days.toFixed(days<10?1:0)} giorni rimasti`: 'giorni non stimabili'}, soglia ${th} ${item.unit}, consiglio ${rec} ${item.unit} (${basis}).`;
  return {th, rec, days, missing, urgency, level, label, reason, velocity:aiVelocity(item), basis};
}
function suggestionScore(item){ const intel=consumptionIntel(item); return intel.urgency + Number(item.usage||0)*5 + Math.max(0, intel.th-Number(item.qty||0))*7; }
function pantryScore(){
  if(!state.length) return 0;
  const scores=state.map(item=>{
    const intel=consumptionIntel(item);
    if(intel.level==='critical') return 18;
    if(intel.level==='low') return 45;
    if(intel.level==='watch') return 68;
    const ratio=Math.min(1.25, Number(item.qty||0)/Math.max(intel.th,1));
    return Math.min(100, Math.round(72 + ratio*22));
  });
  return Math.round(scores.reduce((a,b)=>a+b,0)/scores.length);
}
function householdInsight(){
  const sorted=[...state].sort((a,b)=>suggestionScore(b)-suggestionScore(a));
  const urgent=sorted.filter(i=>statusOf(i)==='buy');
  const next=sorted[0] || null;
  const score=pantryScore();
  const totalDaily=state.reduce((s,i)=>s+aiVelocity(i),0);
  return {score,totalDaily,urgent,next,sorted};
}
function householdInsightText(){
  const h=householdInsight();
  if(!state.length) return 'Non ho ancora abbastanza prodotti reali: fai l’inventario con foto e poi calcolo consumi, giorni rimasti e quantità consigliate.';
  const next=h.next ? `${nameOf(h.next)} (${consumptionIntel(h.next).label})` : 'nessun prodotto critico';
  return `Analisi AI consumi: indice dispensa ${h.score}/100, prodotti da comprare ${h.urgent.length}, prossimo controllo ${next}. Stima consumo totale: ${h.totalDaily.toFixed(1)} unità/giorno, basata su ${settings.people} persone e ${settings.animals} animali più gli eventi registrati.`;
}
function stockPercent(item){ return Math.max(0, Math.min(100, Math.round((1 - (Number(item.qty||0) / Math.max(item.maxQty||1, recommendedQty(item)))) * 100))); }

function newCaptcha(){
  const pool=[
    {id:'milk', label:'Latte', img:BUILTIN_ICON_SRC.milk},
    {id:'water', label:'Acqua', img:BUILTIN_ICON_SRC.water},
    {id:'key', label:'Chiave', img:BUILTIN_ICON_SRC.key},
    {id:'lock', label:'Lucchetto', img:BUILTIN_ICON_SRC.lock},
    {id:'fridge', label:'Frigo', img:BUILTIN_ICON_SRC.fridge}
  ];
  const target=pool[Math.floor(Math.random()*pool.length)];
  const others=pool.filter(x=>x.id!==target.id).sort(()=>Math.random()-.5).slice(0,3);
  const options=[target,...others].sort(()=>Math.random()-.5);
  return {target, options};
}
function renderCaptcha(){
  const box=$('#captchaBox'); if(!box || !$('#regCaptcha')) return;
  $('#regCaptcha').value='';
  const q=$('#captchaQuestion');
  if(q) q.textContent=(t('captchaPickItem')||'Tocca: ')+captcha.target.label;
  box.innerHTML=captcha.options.map(o=>`<button class="captcha-choice" type="button" data-captcha="${esc(o.id)}" aria-label="${esc(o.label)}"><img src="${o.img}" alt="${esc(o.label)}"><span>${esc(o.label)}</span></button>`).join('');
  box.querySelectorAll('[data-captcha]').forEach(btn=>btn.addEventListener('click',()=>{
    box.querySelectorAll('.captcha-choice').forEach(b=>b.classList.remove('active'));
    btn.classList.add('active');
    $('#regCaptcha').value=btn.dataset.captcha;
  }));
}


